     1→import './signup.css'
     2→import React, {useEffect, useState} from "react";
     3→import { useNavigate, Link } from "react-router-dom";
     4→import supabase from '../../utils/supabaseClient';
     5→import Turnstile from 'react-turnstile'
     6→import { MoonLoader } from "react-spinners";
     7→import { useAuth } from '../../Context/useAuth';
     8→
     9→const SITE_KEY = import.meta.env.VITE_SITE_KEY;
    10→
    11→const SignUp = () => {
    12→    const {session, isLoading} = useAuth();
    13→
    14→    const [password, setPassword] = useState(null);
    15→    const [email, setEmail] = useState(null);
    16→    const [showPass, setShowPass] = useState(false)
    17→    const [errorMessage, setErrorMessage] = useState(null);
    18→    const [isLoadingSignUp, setIsLoadingSignUp] = useState(false)
    19→    const navigate = useNavigate(null);
    20→
    21→    const [captchaToken, setCaptchaToken] = useState(null);
    22→
    23→    const handleShowPass = (e) =>{
    24→        e.stopPropagation();
    25→        setShowPass(!showPass)
    26→    }
    27→
    28→    const handleSignUp = async(e) =>{
    29→        e.stopPropagation()
    30→        setIsLoadingSignUp(true)
    31→        const validateEmail = (email) =>{
    32→            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    33→            return emailRegex.test(email)
    34→        }
    35→        if(!validateEmail(email)){
    36→            setIsLoadingSignUp(false)
    37→           return setErrorMessage('Email is not valid')
    38→        }
    39→        if (!captchaToken) {
    40→            setIsLoadingSignUp(false)
    41→            return setErrorMessage("Please complete the CAPTCHA first.");
    42→        }
    43→
    44→        try {
    45→            const res = await fetch(`${import.meta.env.VITE_BACKEND_URL}/verify-turnstile`, {
    46→                method: 'POST',
    47→                headers: { 'Content-Type': 'application/json' },
    48→                body: JSON.stringify({ token: captchaToken }),
    49→            })
    50→
    51→            const result = await res.json();
    52→
    53→            if (!result.success) {
    54→                return setErrorMessage("CAPTCHA verification failed. Try again.");
    55→            }
    56→
    57→            const {error: error} = await supabase.auth.signUp({
    58→                email: email,
    59→                password: password
    60→            })
    61→            if(error.message){
    62→                return setErrorMessage(error.message)
    63→            }
    64→            navigate('/home')
    65→        } catch (error) {
    66→            console.error('Error during sign-up:', error.message);
    67→            setErrorMessage(error.message);
    68→        } finally {
    69→            setEmail(null);
    70→            setPassword(null);
    71→            setIsLoadingSignUp(false)
    72→        }
    73→
    74→    }
    75→    const handleNavigate = (e) => {
    76→        e.stopPropagation();
    77→        return navigate('/login');
    78→    }
    79→    useEffect(() =>{
    80→        if(session){
    81→            return navigate('/home')
    82→        }
    83→    }, [session])
    84→
    85→    if(isLoadingSignUp){
    86→        return(
    87→            <div className='signup-loading-container'>
    88→                <MoonLoader loading={isLoadingSignUp} size={20} speedMultiplier={1} color='rgba(157, 139, 254, 0.8)'/>
    89→            </div>
    90→        )
    91→    }
    92→    return(
    93→        <div className='signup-page-wrapper'>
    94→            <div className='signUp-logo'>
    95→                Iskrib
    96→            </div>
    97→            <p className='signup-tagline'>Where your stories find their voice</p>
    98→
    99→            <div className='signup-page-container'>
   100→                <div className='input-container'>
   101→                    <div className='input-container-child'>
   102→                        <input maxLength={50} value={!email ? '' : email} onChange={(e) => setEmail(e.target.value)} className='signUp-input' type="email" placeholder='Email' aria-label='Email'/>
   103→                        {email&&(
   104→                            <div style={email.length >= 50 ? {color: 'rgb(200, 40, 40)'} : {}} className='length-counter'>
   105→                                {`${email.length}/50`}
   106→                            </div>
   107→                        )}
   108→                    </div>
   109→                    <div className='input-container-child'>
   110→                        <input value={!password ? '' : password} onChange={(e) => setPassword(e.target.value)} className='signUp-input' type={showPass ? 'text' : "password"} placeholder='Password' aria-label='Password'/>
   111→                        {password && (
   112→                            <div onClick={(e) => handleShowPass(e)} className='show-bttn'>
   113→                                {showPass ? 'hide' : 'show'}
   114→                            </div>
   115→                        )}
   116→                    </div>
   117→                    <button onClick={(e) => handleSignUp(e)} disabled={!password} className={!password ? 'submit-bttn submit-bttn-disabled' : 'submit-bttn'}>
   118→                        Submit
   119→                    </button>
   120→                </div>
   121→
   122→                <div className='switch-container'>
   123→                    Have an account? <span onClick={(e) => handleNavigate(e)} className='sign-in-bttn'>Log in</span>
   124→                </div>
   125→
   126→                <div className='captcha-container'>
   127→                    <Turnstile
   128→                    sitekey={SITE_KEY}
   129→                    onVerify={(token) => setCaptchaToken(token)}
   130→                    onExpire={() => setCaptchaToken(null)}
   131→                    onError={() => setCaptchaToken(null)}
   132→                    theme='light'
   133→                    />
   134→                </div>
   135→
   136→                {errorMessage && (
   137→                    <div className='error-message'>
   138→                        {errorMessage}
   139→                    </div>
   140→                )}
   141→            </div>
   142→        </div>
   143→    )
   144→}
   145→export default SignUp;
   146→

