     1→import { useState } from "react";
     2→import { useAuth } from "../../Context/useAuth";
     3→import { addOpinion } from "../../../API/Api";
     4→import { BarLoader } from "react-spinners";
     5→import { useQueryClient } from "@tanstack/react-query";
     6→
     7→const OpinionEditor = ({onClose}) =>{
     8→    const [opinion, setOpinion] = useState('');
     9→    const {session} = useAuth();
    10→    const [isSaving, setIsSaving] = useState(false);
    11→
    12→    const queryClient = useQueryClient();
    13→
    14→    const handleCloseEditor = () =>{
    15→        onClose();
    16→    }
    17→
    18→    const handleClickSave = async(e) =>{
    19→        e.stopPropagation();
    20→        if(isSaving){
    21→            return;
    22→        }
    23→        const formdata = new FormData();
    24→        formdata.append('opinion', opinion)
    25→        
    26→        try {
    27→            setIsSaving(true);
    28→
    29→            const message = await addOpinion(formdata, session?.access_token);
    30→            if(message){
    31→                console.log(message)
    32→            }
    33→            setIsSaving(false)
    34→            queryClient.invalidateQueries(['getOpinions']);
    35→        } catch (error) {
    36→            setIsSaving(false)
    37→            setOpinion('')
    38→            throw new Error('error uploading data')
    39→        } finally {
    40→            setOpinion('')
    41→            onClose();
    42→        }
    43→
    44→    }
    45→
    46→    return(
    47→        <>
    48→        <div className="opinion-editor-parent-container">
    49→            <div className="opinion-editor-container">
    50→                <div className="editor-close-bttn-container">
    51→                    <svg onClick={() => handleCloseEditor()} className="editor-close-bttn" xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="#FFFFFF"><path d="m256-200-56-56 224-224-224-224 56-56 224 224 224-224 56 56-224 224 224 224-56 56-224-224-224 224Z"></path></svg>
    52→                </div>
    53→
    54→                <div className="text-area-container">
    55→                    <textarea maxLength={280} value={opinion} onChange={(e) => setOpinion(e.target.value)} className="opinions-textarea" name="opinions" id="opinions-textarea" placeholder="Share your opinions..."></textarea>
    56→                </div>
    57→                <div style={opinion.length > 279 ? {color: 'red'} : {}} className="text-counter-container">
    58→                    {opinion.length}/280
    59→                </div>
    60→                <div className="opinions-save-bttn-container">
    61→                    <button onClick={(e) => handleClickSave(e)} style={!opinion ? {backgroundColor: '#c8c8c8ff', cursor:'default'} : {}} disabled={!opinion} className="opinions-save-bttn">
    62→                        Save
    63→                    </button>
    64→                </div>
    65→
    66→                {isSaving && (
    67→                    <div className="saving-opinion-loading-container">
    68→                        <BarLoader loading={isSaving} width={'100%'} color="rgb(40, 115, 255)" speedMultiplier={0.7}/>
    69→                    </div>
    70→                )}
    71→                
    72→            </div>
    73→        </div>
    74→        </>
    75→    )
    76→}
    77→
    78→export default OpinionEditor;

